PR #847: Dodaj endpoint eksportu danych użytkowników

Plik: src/controllers/export_controller.rs

```rust
pub async fn export_user_data(
    Query(params): Query<ExportParams>,
    State(db): State<DbPool>,
) -> Result<Response, AppError> {
    let query = format!(
        "SELECT * FROM users WHERE created_at > '{}' AND role = '{}'",
        params.date_from, params.role
    );
    let rows = sqlx::query(&query).fetch_all(&db).await?;

    let mut csv = String::new();
    for row in &rows {
        let email: String = row.get("email");
        let name: String = row.get("name");
        let phone: String = row.get("phone");
        let ssn: String = row.get("ssn");
        csv.push_str(&format!("{},{},{},{}\n", name, email, phone, ssn));
    }

    Ok(Response::builder()
        .header("Content-Type", "text/csv")
        .body(csv.into())?)
}
```
